#include<bits/stdc++.h>
using namespace std;
char a[1000010],b[1000010];
int s[1000010],f[1000010],nxt[1000010],n,m,top;
int main()
{
    scanf("%s%s",a+1,b+1);
    n=strlen(a+1),m=strlen(b+1);
    int j=0;
    for(int i=2;i<=m;i++)
    {
        while(j>0&&b[i]!=b[j+1])
        {
            j=nxt[j];
        }
        if(b[i]==b[j+1])
        {
            j++;
            nxt[i]=j;
        }
    }
    j=0;
    for(int i=1;i<=n;i++)
    {
        while(j>0&&a[i]!=b[j+1])
        {
            j=nxt[j];
        }
        if(a[i]==b[j+1])
        {
            j++;
        }
        s[++top]=i;
        f[i]=j;
        if(j==m)
        {
            top-=m;
            j=f[s[top]];
        }
    }
    for(int i=1;i<=top;i++)
    {
        printf("%c",a[s[i]]);
    }
    return 0;
}
